import React, { useState, useRef, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';
import { useApp } from '../context/AppContext';
import { useToast } from '../context/ToastContext';

const TIER_STYLE = {
  free:   { color: 'var(--mu)',  bg: 'rgba(148,163,184,.15)', label: 'FREE'   },
  growth: { color: 'var(--in2)', bg: 'rgba(99,102,241,.18)',  label: 'GROWTH' },
  prime:  { color: 'var(--go2)', bg: 'rgba(245,158,11,.2)',   label: 'PRIME'  },
};

export function VenueSelector() {
  const { allVenues, activeVenue, switchVenue } = useAuth();
  const { setTier } = useApp();
  const { showToast } = useToast();
  const [open, setOpen] = useState(false);
  const ref = useRef(null);

  useEffect(() => {
    const handler = (e) => { if (ref.current && !ref.current.contains(e.target)) setOpen(false); };
    document.addEventListener('mousedown', handler);
    return () => document.removeEventListener('mousedown', handler);
  }, []);

  // Always render — even with 1 venue the user needs to see which venue is active
  if (!allVenues || allVenues.length === 0) return null;

  const handleSwitch = (venueId) => {
    const v = allVenues.find(x => x.id === venueId);
    if (!v) return;
    switchVenue(venueId);
    setTier(v.tier || 'free');
    setOpen(false);
    showToast(`Switched to ${v.name} ✓`);
  };

  const ts  = TIER_STYLE[activeVenue?.tier] || TIER_STYLE.free;
  const hasMultiple = allVenues.length > 1;

  return (
    <div ref={ref} style={{ position: 'relative', margin: '10px 12px 4px' }}>

      {/* ── Active venue card ── */}
      <div
        onClick={() => hasMultiple && setOpen(o => !o)}
        style={{
          display: 'flex', alignItems: 'center', gap: 10,
          padding: '10px 12px', borderRadius: 'var(--r2)',
          background: open ? 'var(--s2)' : 'var(--s1)',
          border: `1px solid ${open ? 'var(--in)' : 'var(--b1)'}`,
          cursor: hasMultiple ? 'pointer' : 'default',
          transition: 'all .15s',
          userSelect: 'none',
        }}
      >
        {/* Venue avatar */}
        <div style={{
          width: 36, height: 36, borderRadius: 9, flexShrink: 0,
          background: 'linear-gradient(135deg,var(--in),var(--pu))',
          display: 'flex', alignItems: 'center', justifyContent: 'center',
          fontSize: 15, fontWeight: 800, color: '#fff',
        }}>
          {(activeVenue?.name || 'V').charAt(0)}
        </div>

        <div style={{ flex: 1, minWidth: 0 }}>
          <div style={{ fontSize: 13, fontWeight: 700, color: 'var(--tx)', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
            {activeVenue?.name || 'Select venue'}
          </div>
          <div style={{ fontSize: 11, color: 'var(--mu)', marginTop: 1, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
            {activeVenue?.location || 'No location'}
          </div>
        </div>

        <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'flex-end', gap: 4, flexShrink: 0 }}>
          <span style={{ fontSize: 9, fontWeight: 700, padding: '2px 8px', borderRadius: 10, background: ts.bg, color: ts.color }}>
            {ts.label}
          </span>
          {hasMultiple && (
            <span style={{ fontSize: 10, color: 'var(--mu)', transition: 'transform .2s', transform: open ? 'rotate(180deg)' : 'rotate(0deg)', display: 'block' }}>▾</span>
          )}
        </div>
      </div>

      {/* ── Venue count badge ── */}
      {hasMultiple && (
        <div style={{ fontSize: 10, color: 'var(--mu)', padding: '3px 12px 0', display: 'flex', alignItems: 'center', gap: 4 }}>
          <span style={{ width: 5, height: 5, borderRadius: '50%', background: 'var(--gn)', display: 'inline-block' }} />
          {allVenues.length} venues · tap to switch
        </div>
      )}

      {/* ── Dropdown ── */}
      {open && (
        <div style={{
          position: 'absolute', top: 'calc(100% + 6px)', left: 0, right: 0,
          background: 'var(--bg3)', border: '1px solid var(--b2)',
          borderRadius: 'var(--r2)', boxShadow: '0 16px 48px rgba(0,0,0,.6)',
          zIndex: 100, overflow: 'hidden',
        }}>
          <div style={{ padding: '8px 12px 6px', fontSize: 10, color: 'var(--dim)', fontWeight: 700, textTransform: 'uppercase', letterSpacing: '1px', borderBottom: '1px solid var(--b1)' }}>
            Switch venue ({allVenues.length})
          </div>

          {allVenues.map((v) => {
            const isActive = v.id === activeVenue?.id;
            const s = TIER_STYLE[v.tier] || TIER_STYLE.free;
            return (
              <div
                key={v.id}
                onClick={() => !isActive && handleSwitch(v.id)}
                style={{
                  display: 'flex', alignItems: 'center', gap: 10,
                  padding: '11px 12px',
                  cursor: isActive ? 'default' : 'pointer',
                  background: isActive ? 'rgba(99,102,241,.1)' : 'transparent',
                  borderLeft: `3px solid ${isActive ? 'var(--in)' : 'transparent'}`,
                  borderBottom: '1px solid var(--b1)',
                  transition: 'background .12s',
                }}
                onMouseEnter={e => { if (!isActive) e.currentTarget.style.background = 'var(--s1)'; }}
                onMouseLeave={e => { if (!isActive) e.currentTarget.style.background = 'transparent'; }}
              >
                {/* Venue letter avatar */}
                <div style={{
                  width: 34, height: 34, borderRadius: 8, flexShrink: 0,
                  background: isActive
                    ? 'linear-gradient(135deg,var(--in),var(--pu))'
                    : 'var(--s2)',
                  display: 'flex', alignItems: 'center', justifyContent: 'center',
                  fontSize: 13, fontWeight: 800,
                  color: isActive ? '#fff' : 'var(--mu)',
                  border: isActive ? 'none' : '1px solid var(--b1)',
                }}>
                  {v.name.charAt(0)}
                </div>

                <div style={{ flex: 1, minWidth: 0 }}>
                  <div style={{ fontSize: 13, fontWeight: isActive ? 700 : 400, color: 'var(--tx)', display: 'flex', alignItems: 'center', gap: 6, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
                    {v.name}
                    {isActive && <span style={{ fontSize: 9, color: 'var(--in2)', fontWeight: 700 }}>● ACTIVE</span>}
                  </div>
                  <div style={{ fontSize: 11, color: 'var(--mu)', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap', marginTop: 1 }}>
                    {v.location}
                  </div>
                </div>

                <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'flex-end', gap: 3, flexShrink: 0 }}>
                  <span style={{ fontSize: 9, fontWeight: 700, padding: '2px 7px', borderRadius: 10, background: s.bg, color: s.color }}>
                    {s.label}
                  </span>
                  <span style={{ fontSize: 10, color: v.nc_balance < 5000 ? 'var(--rd2)' : 'var(--dim)' }}>
                    {(v.nc_balance || 0).toLocaleString('en-IN')} NC
                  </span>
                </div>
              </div>
            );
          })}

          {/* Add venue */}
          <div style={{ padding: '8px 12px 10px' }}>
            <button
              onClick={() => { setOpen(false); showToast('To add a new venue, contact support@nyto.app'); }}
              style={{ width: '100%', padding: '7px', background: 'transparent', border: '1px dashed var(--b2)', borderRadius: 7, color: 'var(--mu)', fontSize: 12, cursor: 'pointer', fontFamily: 'inherit', transition: 'all .15s' }}
              onMouseEnter={e => { e.currentTarget.style.borderColor = 'var(--in)'; e.currentTarget.style.color = 'var(--in2)'; }}
              onMouseLeave={e => { e.currentTarget.style.borderColor = 'var(--b2)'; e.currentTarget.style.color = 'var(--mu)'; }}
            >
              + Add another venue
            </button>
          </div>
        </div>
      )}
    </div>
  );
}
